class Solution {
public:
    int leastOpsExpressTarget(int x, int target) {
        int res = 0;
        while (target > 0) {
            if (target % x == 0) {
                res += target / x - 1;
                target = 1;
            } else if (target > x) {
                int p = target / x;
                if (p * x - target < target - (p - 1) * x) {
                    res += p;
                    target = target - p * x;
                } else {
                    res += p - 1;
                    target = (p - 1) * x - target;
                }
            } else {
                res += target - 1;
                target = 1;
            }
        }
        return res;
    }
};
